// Récupération de l'objet utilisateur
const user = pluginVariables['1fa0dd68-5069-436c-9a7d-3b54c340f1fa']['user'];

// Fonction pour formater un objet de manière lisible
function formatObject(obj, indent = 0) {
  if (obj === null || obj === undefined) {
    return 'null';
  }

  if (typeof obj !== 'object') {
    return String(obj);
  }

  const spaces = '  '.repeat(indent);
  const nextSpaces = '  '.repeat(indent + 1);

  if (Array.isArray(obj)) {
    if (obj.length === 0) return '[]';
    const items = obj.map(item => nextSpaces + formatObject(item, indent + 1)).join(',\n');
    return `[\n${items}\n${spaces}]`;
  }

  const keys = Object.keys(obj);
  if (keys.length === 0) return '{}';

  const items = keys.map(key => {
    const value = formatObject(obj[key], indent + 1);
    return `${nextSpaces}${key}: ${value}`;
  }).join(',\n');

  return `{\n${items}\n${spaces}}`;
}

// Formatage de l'objet utilisateur
const formattedUser = formatObject(user);

// Création d'un résumé lisible
const summary = `
=== INFORMATIONS UTILISATEUR ===

ID: ${user?.id || 'Non défini'}
Email: ${user?.email || 'Non défini'}
Rôle: ${user?.role || 'Non défini'}
Statut: ${user?.aud || 'Non défini'}
Email confirmé: ${user?.email_confirmed_at ? 'Oui (' + user.email_confirmed_at + ')' : 'Non'}
Téléphone: ${user?.phone || 'Non renseigné'}
Date de confirmation: ${user?.confirmed_at || 'Non défini'}

=== OBJET COMPLET ===
${formattedUser}
`;

return summary;

